from __future__ import annotations
import json
import time
import logging
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Optional
from openai import OpenAI
import os

log = logging.getLogger(__name__)
client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])


# ── Core agent types ───────────────────────────────────────────────────────────

class ActionType(Enum):
    TOOL_CALL = 'tool_call'
    RESPOND = 'respond'
    PLAN = 'plan'
    WAIT = 'wait'


@dataclass
class AgentAction:
    type: ActionType
    tool_name: Optional[str] = None
    tool_args: Optional[dict] = None
    response: Optional[str] = None
    reasoning: str = ''


@dataclass
class AgentStep:
    step_number: int
    action: AgentAction
    observation: str
    timestamp: float = field(default_factory=time.time)
    success: bool = True


@dataclass
class AgentState:
    task: str
    steps: list[AgentStep] = field(default_factory=list)
    is_complete: bool = False
    final_answer: str = ''
    total_cost_usd: float = 0.0

    def add_step(self, action: AgentAction, observation: str, success: bool = True) -> None:
        self.steps.append(AgentStep(
            step_number=len(self.steps) + 1,
            action=action,
            observation=observation,
            success=success,
        ))

    def to_context(self) -> str:
        """Format previous steps for the agent's context window."""
        if not self.steps:
            return ''
        lines = ['Previous steps:']
        for step in self.steps[-5:]:  # last 5 steps to bound context
            a = step.action
            if a.type == ActionType.TOOL_CALL:
                lines.append(f'Step {step.step_number}: Called {a.tool_name}({a.tool_args}) → {step.observation[:150]}')
            else:
                lines.append(f'Step {step.step_number}: {a.response[:150] if a.response else ""}')
        return '\n'.join(lines)


# ── Tool base class ────────────────────────────────────────────────────────────

class Tool(ABC):
    @property
    @abstractmethod
    def name(self) -> str: ...

    @property
    @abstractmethod
    def description(self) -> str: ...

    @property
    @abstractmethod
    def schema(self) -> dict: ...

    @abstractmethod
    def execute(self, **kwargs) -> str: ...

    def to_openai_spec(self) -> dict:
        return {'type': 'function', 'function': {'name': self.name, 'description': self.description, 'parameters': self.schema}}


# ── Concrete tools ─────────────────────────────────────────────────────────────

class WebSearchTool(Tool):
    name = 'web_search'
    description = 'Search the web for current information. Returns top 3 relevant snippets.'
    schema = {'type': 'object', 'properties': {'query': {'type': 'string', 'description': 'Search query'}}, 'required': ['query']}

    def execute(self, query: str) -> str:
        # Simulated results — in production: SerpAPI, Tavily, DuckDuckGo
        return json.dumps([
            {'title': f'Result 1 for: {query}', 'snippet': f'Information about {query}...', 'url': 'https://example.com/1'},
            {'title': f'Result 2 for: {query}', 'snippet': f'More details on {query}...', 'url': 'https://example.com/2'},
        ])


class CodeExecutorTool(Tool):
    name = 'execute_python'
    description = 'Execute a Python code snippet. Returns stdout output or error message.'
    schema = {
        'type': 'object',
        'properties': {'code': {'type': 'string', 'description': 'Python code to execute'}},
        'required': ['code'],
    }

    def execute(self, code: str) -> str:
        import io
        import contextlib
        stdout = io.StringIO()
        try:
            # CAUTION: use a sandbox (e2b.dev, subprocess with timeout) in production
            with contextlib.redirect_stdout(stdout):
                exec(code, {'__builtins__': {'print': print, 'range': range, 'len': len, 'sum': sum, 'sorted': sorted}})  # noqa: S102
            return stdout.getvalue() or '(no output)'
        except Exception as e:
            return f'ERROR: {type(e).__name__}: {e}'


class MemoryTool(Tool):
    name = 'remember'
    description = 'Store a key fact in memory for use in future steps.'
    schema = {
        'type': 'object',
        'properties': {
            'key': {'type': 'string'},
            'value': {'type': 'string'},
        },
        'required': ['key', 'value'],
    }

    def __init__(self):
        self._store: dict[str, str] = {}

    def execute(self, key: str, value: str) -> str:
        self._store[key] = value
        return f'Stored: {key} = {value}'

    def recall(self, key: str) -> Optional[str]:
        return self._store.get(key)

    def all_facts(self) -> str:
        return json.dumps(self._store)


# ── Base agent ─────────────────────────────────────────────────────────────────

class BaseAgent:
    def __init__(
        self,
        tools: list[Tool],
        model: str = 'gpt-4o-mini',
        max_steps: int = 10,
        system_prompt: str = '',
    ):
        self.tools = {t.name: t for t in tools}
        self.model = model
        self.max_steps = max_steps
        self.system_prompt = system_prompt or (
            'You are an autonomous AI agent. Complete tasks step by step using available tools. '
            'When you have enough information to answer, respond with your final answer.'
        )

    def _build_messages(self, state: AgentState) -> list[dict]:
        context = state.to_context()
        system = self.system_prompt
        if context:
            system += f'\n\n{context}'
        return [
            {'role': 'system', 'content': system},
            {'role': 'user', 'content': state.task},
        ]

    def _dispatch_tool(self, name: str, args: dict) -> str:
        tool = self.tools.get(name)
        if tool is None:
            return json.dumps({'error': f'Unknown tool: {name}'})
        try:
            return tool.execute(**args)
        except Exception as e:
            return json.dumps({'error': str(e)})

    def run(self, task: str) -> AgentState:
        state = AgentState(task=task)
        messages = self._build_messages(state)
        tools_spec = [t.to_openai_spec() for t in self.tools.values()]

        for step in range(self.max_steps):
            response = client.chat.completions.create(
                model=self.model,
                messages=messages,
                tools=tools_spec,
                tool_choice='auto',
            )
            msg = response.choices[0].message
            messages.append(msg)

            if not msg.tool_calls:  # final response
                action = AgentAction(type=ActionType.RESPOND, response=msg.content)
                state.add_step(action, 'Task complete')
                state.is_complete = True
                state.final_answer = msg.content
                log.info('Agent complete after %d steps', step + 1)
                return state

            # Execute tool calls
            for tc in msg.tool_calls:
                args = json.loads(tc.function.arguments)
                result = self._dispatch_tool(tc.function.name, args)
                log.info('Step %d: %s(%s) → %s', step + 1, tc.function.name, args, result[:80])

                action = AgentAction(
                    type=ActionType.TOOL_CALL,
                    tool_name=tc.function.name,
                    tool_args=args,
                )
                state.add_step(action, result)
                messages.append({'role': 'tool', 'tool_call_id': tc.id, 'content': result})

        state.final_answer = 'Max steps reached without completing the task.'
        return state


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    tools = [WebSearchTool(), CodeExecutorTool(), MemoryTool()]
    agent = BaseAgent(tools=tools, model='gpt-4o-mini', max_steps=5)

    tasks = [
        'Calculate the sum of squares from 1 to 10 using Python code.',
        'Search for information about the Transformer architecture, then summarize the key innovation in one sentence.',
    ]

    for task in tasks:
        print(f'\n=== Task: {task} ===')
        state = agent.run(task)
        print(f'Steps taken: {len(state.steps)}')
        print(f'Answer: {state.final_answer}')
        for step in state.steps:
            a = step.action
            if a.tool_name:
                print(f'  [{step.step_number}] {a.tool_name}({a.tool_args}) → {step.observation[:60]}...')
